const allMessages = $input.all().map(i => i.json);
const cutoffTs = (Date.now() / 1000) - (30 * 60);
const messages = allMessages.filter(m => m.ts && parseFloat(m.ts) >= cutoffTs);
const workspace = $('Extract Workspaces').first().json;

const BLOCKER_PATTERNS = [
  { type: 'blocker', keywords: ['blocked', 'blocking', 'stuck', "can't proceed", 'cannot proceed', 'unable to proceed'] },
  { type: 'dependency', keywords: ['waiting on', 'waiting for', 'depends on', 'dependency'] },
  { type: 'risk', keywords: ['at risk', 'might miss', 'could miss', 'concern', 'worried about', 'escalate'] },
  { type: 'decision', keywords: ['need decision', 'needs decision', 'waiting for approval', 'need sign-off', 'need sign off'] }
];

function classifyMessage(text) {
  const lower = text.toLowerCase();
  for (const { type, keywords } of BLOCKER_PATTERNS) {
    const matched = keywords.filter(k => lower.includes(k));
    if (matched.length > 0) return { type, keywords: matched };
  }
  return null;
}

const channelId = workspace.slack_channel_id ?? $env.SLACK_CHANNEL_ID;

const signals = [];
for (const msg of messages) {
  if (!msg.text || msg.subtype) continue;
  const classification = classifyMessage(msg.text);
  if (!classification) continue;
  signals.push({
    message_ts: msg.ts,
    channel_id: channelId,
    author_id: msg.user ?? msg.username ?? 'unknown',
    text: msg.text.slice(0, 2000),
    signal_type: classification.type,
    matched_keywords: classification.keywords,
    detected_at: new Date(parseFloat(msg.ts) * 1000).toISOString()
  });
}

return [{ json: {
  workspace_id: workspace.id,
  signals,
  channel_id: channelId,
  synced_at: new Date().toISOString()
}}];
